import{c as o,Q as e,j as i,m as n}from"./chunks/framework.BPKcPtvA.js";const j=JSON.parse('{"title":"Jobs-To-Be-Done (JTBD) Platno","description":"Analiza JTBD okvira, funkcionalni, socijalni i emocionalni poslovi koje obavlja AI orkestrator","frontmatter":{"title":"Jobs-To-Be-Done (JTBD) Platno","description":"Analiza JTBD okvira, funkcionalni, socijalni i emocionalni poslovi koje obavlja AI orkestrator","keywords":"JTBD, customer success, value proposition, user goals","robots":"index, follow"},"headers":[],"relativePath":"jtbd/index.md","filePath":"jtbd/index.md","lastUpdated":null}'),t={name:"jtbd/index.md"};function r(s,a,l,d,p,u){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="🎯-jobs-to-be-done-jtbd-platno" tabindex="-1">🎯 Jobs-To-Be-Done (JTBD) Platno <a class="header-anchor" href="#🎯-jobs-to-be-done-jtbd-platno" aria-label="Permalink to &quot;🎯 Jobs-To-Be-Done (JTBD) Platno&quot;">​</a></h1><p>Kako bismo precizno pozicionirali <strong>AI Workflow Orchestrator</strong> na tržištu bezbedne AI automatizacije, primenili smo <strong>JTBD (Jobs-To-Be-Done)</strong> teoriju. Ovaj okvir identifikuje stvarne funkcionalne, socijalne i emocionalne poslove za koje naši klijenti &quot;unajmljuju&quot; naš sistem.</p><hr><h2 id="🖼️-pregled-jtbd-platna-jtbd-canvas" tabindex="-1">🖼️ Pregled JTBD Platna (JTBD Canvas) <a class="header-anchor" href="#🖼️-pregled-jtbd-platna-jtbd-canvas" aria-label="Permalink to &quot;🖼️ Pregled JTBD Platna (JTBD Canvas)&quot;">​</a></h2><p>Sledeći dijagram prikazuje tri dimenzije posla koji naš sistem obavlja:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                            [ JTBD OKVIR ]</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>    ┌─────────────────────────────┼─────────────────────────────┐</span></span>
<span class="line"><span>    ▼                             ▼                             ▼</span></span>
<span class="line"><span>[ Funkcionalni Posao ]        [ Emocionalni Posao ]         [ Socijalni Posao ]</span></span>
<span class="line"><span>- Orkestracija bezbednog      - Miran san i sigurnost       - Izgradnja ugleda lidera</span></span>
<span class="line"><span>  koda i deploymenta.           da AI neće srušiti sistem.    koji uvodi siguran AI.</span></span></code></pre></div><hr><h2 id="🛠️-tri-dimenzije-posla-the-job-map" tabindex="-1">🛠️ Tri Dimenzije Posla (The Job Map) <a class="header-anchor" href="#🛠️-tri-dimenzije-posla-the-job-map" aria-label="Permalink to &quot;🛠️ Tri Dimenzije Posla (The Job Map)&quot;">​</a></h2><h3 id="_1-primarni-funkcionalni-posao-primary-functional-job" tabindex="-1">1. Primarni Funkcionalni Posao (Primary Functional Job) <a class="header-anchor" href="#_1-primarni-funkcionalni-posao-primary-functional-job" aria-label="Permalink to &quot;1. Primarni Funkcionalni Posao (Primary Functional Job)&quot;">​</a></h3><blockquote><p><em>&quot;Kada podižem i konfigurišem složenu cloud infrastrukturu, želim da koristim bezbedan i autonoman AI sistem koji prepoznaje rizike pre nego što pokrene bilo kakav kod, kako bih smanjio udeo manuelnog rada i izbegao bezbednosne propuste.&quot;</em></p></blockquote><h3 id="_2-emocionalni-posao-emotional-job" tabindex="-1">2. Emocionalni Posao (Emotional Job) <a class="header-anchor" href="#_2-emocionalni-posao-emotional-job" aria-label="Permalink to &quot;2. Emocionalni Posao (Emotional Job)&quot;">​</a></h3><ul><li><strong>Otklanjanje straha:</strong> Pružanje potpunog osećaja sigurnosti DevOps i SRE inženjerima da autonomni AI agenti neće doneti katastrofalne konfiguracione odluke ili izbrisati kritične baze podataka na produkciji.</li><li><strong>Kontrola i mir:</strong> Poverenje u to da sistem ima ugrađene automatske prekidače (circuit breaker-e) koji drže finansijske troškove pod strogom kontrolom.</li></ul><h3 id="_3-socijalni-posao-social-job" tabindex="-1">3. Socijalni Posao (Social Job) <a class="header-anchor" href="#_3-socijalni-posao-social-job" aria-label="Permalink to &quot;3. Socijalni Posao (Social Job)&quot;">​</a></h3><ul><li><strong>Pozicioniranje lidera:</strong> Omogućavanje inženjerskim menadžerima da se u svojim kompanijama pozicioniraju kao inovatori koji uspešno i bezbedno uvode napredne multi-agent sisteme, bez ugrožavanja PCI-DSS ili SOC2 usklađenosti.</li><li><strong>Gostoprimstvo i poverenje:</strong> Izgradnja reputacije stabilnog tima koji isporučuje pouzdana rešenja brže od konkurencije.</li></ul><hr><h2 id="📈-zeljeni-ishodi-i-metrike-uspeha-outcome-metrics" tabindex="-1">📈 Željeni Ishodi i Metrike Uspeha (Outcome Metrics) <a class="header-anchor" href="#📈-zeljeni-ishodi-i-metrike-uspeha-outcome-metrics" aria-label="Permalink to &quot;📈 Željeni Ishodi i Metrike Uspeha (Outcome Metrics)&quot;">​</a></h2><p>Kako klijenti mere uspeh kada &quot;unajme&quot; naš sistem? Primenjujemo sledeće metrike:</p><table tabindex="0"><thead><tr><th>Cilj klijenta</th><th>Metrika uspeha</th><th>Ciljana vrednost</th></tr></thead><tbody><tr><td><strong>Smanjenje ručnog debugovanja</strong></td><td>Vreme oporavka od greške (MTTR) kroz Self-Healing</td><td>$&lt; 10$ sekundi</td></tr><tr><td><strong>Sprečavanje privilegovanih bežanja</strong></td><td>Stopa detekcije nebezbednih admission komandi</td><td>$100%$ provera</td></tr><tr><td><strong>Kontrola troškova LLM API-ja</strong></td><td>Stopa odbijanja upita usled prekoračenja tokena</td><td>$0%$ probijanja limita</td></tr><tr><td><strong>Auditabilnost i provera odluka</strong></td><td>Dostupnost detaljnog debate trace-a u logovima</td><td>$100%$ pokrivenost</td></tr></tbody></table><hr><h2 id="⚖️-alternativna-i-konkurentska-resenja" tabindex="-1">⚖️ Alternativna i Konkurentska Rešenja <a class="header-anchor" href="#⚖️-alternativna-i-konkurentska-resenja" aria-label="Permalink to &quot;⚖️ Alternativna i Konkurentska Rešenja&quot;">​</a></h2><p>Kada korisnici nemaju naš sistem, oni se oslanjaju na sledeća nebezbedna rešenja:</p><ol><li><strong>Manuelni rad (DevOps inženjeri):</strong> Pisanje Terraform i Ansible skripti ručno. <em>Problem:</em> Sporo, sklono ljudskim greškama i slabo skalabilno.</li><li><strong>Standardni AI agenti (npr. bazični AutoGPT):</strong> AI agenti bez debata i nultog poverenja. <em>Problem:</em> Visok rizik od curenja podataka, nepredvidivi troškovi i sklonost halucinacijama bez provere.</li><li><strong>Tradicionalni CI/CD pajplajnovi:</strong> <em>Problem:</em> Statični su, ne mogu se dinamički samoisceljivati i prilagođavati novim OS greškama u realnom vremenu.</li></ol>`,22)])])}const k=o(t,[["render",r]]);export{j as __pageData,k as default};
